"""stl_validator_improved.py — improved STL validation tool.

Supports both ASCII and binary STL files. Checks:
  - Triangle count
  - Surface area
  - Manifold integrity (open edges AND non-manifold edges with count > 2)
  - Face normal consistency (declared vs computed from winding)
  - Degenerate (zero-area) triangles
  - Duplicate faces
  - Minimum triangle count for a closed solid
"""
import json
import math
import struct
import sys


# ---------------------------------------------------------------------------
# Math helpers
# ---------------------------------------------------------------------------

def _cross(a, b):
    return (
        a[1] * b[2] - a[2] * b[1],
        a[2] * b[0] - a[0] * b[2],
        a[0] * b[1] - a[1] * b[0],
    )


def _sub(a, b):
    return (a[0] - b[0], a[1] - b[1], a[2] - b[2])


def _dot(a, b):
    return a[0] * b[0] + a[1] * b[1] + a[2] * b[2]


def _magnitude(v):
    return math.sqrt(v[0] ** 2 + v[1] ** 2 + v[2] ** 2)


def _normalize(v):
    m = _magnitude(v)
    if m < 1e-10:
        return (0.0, 0.0, 0.0)
    return (v[0] / m, v[1] / m, v[2] / m)


def _triangle_area(v1, v2, v3):
    return 0.5 * _magnitude(_cross(_sub(v2, v1), _sub(v3, v1)))


# ---------------------------------------------------------------------------
# STL parsers
# ---------------------------------------------------------------------------

def _is_binary_stl(path: str) -> bool:
    """Heuristic: binary STL has an 80-byte header + 4-byte triangle count."""
    try:
        with open(path, "rb") as fh:
            header = fh.read(80)
            if len(header) < 80:
                return False
            # If the file starts with 'solid', it's likely ASCII
            # (though some binary files also start with 'solid')
            count_bytes = fh.read(4)
            if len(count_bytes) < 4:
                return False
            count = struct.unpack('<I', count_bytes)[0]
            fh.seek(0, 2)  # seek to end
            file_size = fh.tell()
            expected_size = 80 + 4 + count * 50
            # If file size matches binary expectation, it's binary
            if file_size == expected_size:
                return True
    except Exception:
        pass
    return False


def _parse_ascii_stl(path: str) -> tuple:
    """Parse ASCII STL. Returns (triangles, issues).
    triangles = list of (declared_normal, [v1, v2, v3])
    """
    issues = []
    triangles = []

    with open(path, "r", errors="replace") as fh:
        lines = fh.readlines()

    i = 0
    while i < len(lines):
        line = lines[i].strip()

        if line.startswith("facet normal"):
            parts = line.split()
            try:
                declared_normal = (float(parts[2]), float(parts[3]), float(parts[4]))
            except (IndexError, ValueError):
                issues.append(f"Malformed facet normal at line {i + 1}")
                i += 1
                continue

            vertices = []
            i += 1
            if i < len(lines) and lines[i].strip() == "outer loop":
                i += 1
                for _ in range(3):
                    if i < len(lines):
                        vline = lines[i].strip()
                        if vline.startswith("vertex"):
                            vparts = vline.split()
                            try:
                                vertices.append(
                                    (
                                        float(vparts[1]),
                                        float(vparts[2]),
                                        float(vparts[3]),
                                    )
                                )
                            except (IndexError, ValueError):
                                issues.append(f"Malformed vertex at line {i + 1}")
                        i += 1

            if len(vertices) == 3:
                triangles.append((declared_normal, vertices))
            else:
                issues.append(f"Incomplete triangle near line {i + 1}")
            continue

        i += 1

    return triangles, issues


def _parse_binary_stl(path: str) -> tuple:
    """Parse binary STL. Returns (triangles, issues)."""
    issues = []
    triangles = []

    with open(path, "rb") as fh:
        fh.read(80)  # skip header
        count_bytes = fh.read(4)
        if len(count_bytes) < 4:
            return triangles, ["Binary STL file too short to contain triangle count"]
        count = struct.unpack('<I', count_bytes)[0]

        for idx in range(count):
            data = fh.read(50)
            if len(data) < 50:
                issues.append(f"Truncated binary STL at triangle {idx + 1}")
                break
            nx, ny, nz = struct.unpack('<fff', data[0:12])
            v1 = struct.unpack('<fff', data[12:24])
            v2 = struct.unpack('<fff', data[24:36])
            v3 = struct.unpack('<fff', data[36:48])
            # attr_byte_count = struct.unpack('<H', data[48:50])
            triangles.append(((nx, ny, nz), [v1, v2, v3]))

    return triangles, issues


# ---------------------------------------------------------------------------
# Main validation
# ---------------------------------------------------------------------------

def parse_stl(path: str) -> dict:
    """Validate an STL file and return a results dictionary."""
    # Detect format
    if _is_binary_stl(path):
        triangles, issues = _parse_binary_stl(path)
    else:
        triangles, issues = _parse_ascii_stl(path)

    if not triangles:
        issues.append("No valid faces found")
        return {
            "valid": False,
            "triangle_count": 0,
            "surface_area": 0.0,
            "issues": issues,
        }

    # -- Degenerate triangle check --
    degenerate_count = 0
    for _, verts in triangles:
        area = _triangle_area(*verts)
        if area < 1e-10:
            degenerate_count += 1
    if degenerate_count > 0:
        issues.append(f"Mesh has {degenerate_count} degenerate (zero-area) triangle(s)")

    # -- Duplicate face check --
    face_set = {}
    duplicate_count = 0
    for _, verts in triangles:
        rounded = tuple(sorted(tuple(round(x, 6) for x in v) for v in verts))
        face_set[rounded] = face_set.get(rounded, 0) + 1
    duplicate_count = sum(1 for cnt in face_set.values() if cnt > 1)
    if duplicate_count > 0:
        issues.append(f"Mesh has {duplicate_count} duplicate face(s)")

    # -- Manifold check --
    # Every edge must be shared by exactly 2 triangles.
    edge_count: dict = {}
    for _, verts in triangles:
        rounded = [tuple(round(x, 6) for x in v) for v in verts]
        for j in range(3):
            edge = tuple(sorted([rounded[j], rounded[(j + 1) % 3]]))
            edge_count[edge] = edge_count.get(edge, 0) + 1

    open_edges = sum(1 for cnt in edge_count.values() if cnt == 1)
    non_manifold_edges = sum(1 for cnt in edge_count.values() if cnt > 2)

    if open_edges > 0:
        issues.append(f"Mesh has {open_edges} open edge(s) — not a closed solid")
    if non_manifold_edges > 0:
        issues.append(
            f"Mesh has {non_manifold_edges} non-manifold edge(s) (shared by >2 triangles)"
        )

    # -- Normal consistency check --
    # BUG IN PROVIDED TOOL: threshold was -0.99, which only catches nearly-perfectly
    # inverted normals. Should be < 0 (any normal pointing in wrong hemisphere).
    # However, we also allow a small tolerance for floating-point error, so threshold
    # is set to < -0.5 to catch clear inversions while tolerating minor precision issues.
    # For strict validation we use < 0.
    inverted_normal_count = 0
    misaligned_normal_count = 0
    for declared_normal, verts in triangles:
        edge1 = _sub(verts[1], verts[0])
        edge2 = _sub(verts[2], verts[0])
        cross = _cross(edge1, edge2)
        if _magnitude(cross) < 1e-10:
            continue  # degenerate triangle, skip normal check
        winding_normal = _normalize(cross)
        dn_norm = _normalize(declared_normal)
        # If declared normal is zero vector, skip
        if _magnitude(declared_normal) < 1e-10:
            continue
        similarity = _dot(dn_norm, winding_normal)
        if similarity < -0.5:  # clearly inverted (> 120 degrees off)
            inverted_normal_count += 1
        elif similarity < 0.5:  # significantly misaligned (> 60 degrees off)
            misaligned_normal_count += 1

    if inverted_normal_count > 0:
        issues.append(
            f"{inverted_normal_count} face normal(s) are inverted relative to winding order"
        )
    if misaligned_normal_count > 0:
        issues.append(
            f"{misaligned_normal_count} face normal(s) are significantly misaligned "
            f"with winding order (>60° off)"
        )

    # -- Minimum triangle count --
    if len(triangles) < 4:
        issues.append(
            f"Too few triangles ({len(triangles)}) — minimum 4 required for a closed solid"
        )

    surface_area = sum(_triangle_area(*verts) for _, verts in triangles)

    return {
        "valid": len(issues) == 0,
        "format": "binary" if _is_binary_stl(path) else "ascii",
        "triangle_count": len(triangles),
        "surface_area": round(surface_area, 6),
        "issues": issues,
    }


def validate_for_manufacturing(path: str) -> dict:
    """High-level manufacturing suitability check.
    Returns result with 'suitable_for_manufacturing' boolean and summary.
    """
    result = parse_stl(path)
    result["suitable_for_manufacturing"] = result["valid"]
    if result["valid"]:
        result["summary"] = "File passes all checks and is suitable for manufacturing."
    else:
        result["summary"] = (
            f"File has {len(result['issues'])} issue(s) and is NOT suitable for manufacturing."
        )
    return result


if __name__ == "__main__":
    if len(sys.argv) < 2:
        print(json.dumps({"error": "usage: stl_validator_improved.py <file.stl>"}))
        sys.exit(1)
    print(json.dumps(validate_for_manufacturing(sys.argv[1]), indent=2))

